export const getGetH2HUrl = (params: GetH2HParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/h2h?${stringifiedParams}`
    : `/api/h2h`;
};

export const getH2H = async (
  params: GetH2HParams,
  options?: RequestInit,
): Promise<H2HSummary> => {
  return customFetch<H2HSummary>(getGetH2HUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetH2HQueryKey = (params?: GetH2HParams) => {
  return [`/api/h2h`, ...(params ? [params] : [])] as const;
};

export const getGetH2HQueryOptions = <
  TData = Awaited<ReturnType<typeof getH2H>>,
  TError = ErrorType<unknown>,
>(
  params: GetH2HParams,
  options?: {
    query?: UseQueryOptions<Awaited<ReturnType<typeof getH2H>>, TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetH2HQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getH2H>>> = ({
    signal,
  }) => getH2H(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getH2H>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetH2HQueryResult = NonNullable<Awaited<ReturnType<typeof getH2H>>>;
export type GetH2HQueryError = ErrorType<unknown>;

/**
 * @summary Head-to-head history
 */

export function useGetH2H<
  TData = Awaited<ReturnType<typeof getH2H>>,
  TError = ErrorType<unknown>,
>(
  params: GetH2HParams,
  options?: {
    query?: UseQueryOptions<Awaited<ReturnType<typeof getH2H>>, TError, TData>;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetH2HQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

